import React from 'react';
import { FileText, ArrowRight } from 'lucide-react'; // Importa ArrowRight
import MultiSectionForm from './MultiSectionForm';

const FormsPage = () => {
  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-4">Legal Forms</h1>
        <p className="text-gray-600 dark:text-gray-300">
          Complete and submit legal forms efficiently. Please ensure all information is accurate before submission.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        {formCards.map((card, index) => (
          <FormCard
            key={index}
            title={card.title}
            description={card.description}
            icon={card.icon}
            active={card.active}
            disabled={card.disabled}
          />
        ))}
      </div>

      <MultiSectionForm />
    </div>
  );
};

const formCards = [
  {
    title: "Document Filing",
    description: "Submit new legal documents and filings",
    icon: FileText,
    active: true,
    disabled: false
  },
  {
    title: "Motion Templates",
    description: "Access and fill standard motion forms",
    icon: FileText,
    active: false,
    disabled: true
  },
  {
    title: "Court Submissions",
    description: "Submit documents directly to court",
    icon: FileText,
    active: false,
    disabled: true
  }
];

const FormCard = ({ title, description, icon: Icon, active, disabled }) => {
  return (
    <div
      className={`relative p-6 bg-white dark:bg-gray-800 rounded-lg shadow-sm border-2 
        ${active ? 'border-blue-500' : 'border-transparent'}
        ${disabled ? 'opacity-50 cursor-not-allowed' : 'hover:border-blue-500 cursor-pointer'}
      `}
    >
      <div className="flex items-start">
        <div className="flex-shrink-0">
          <Icon className="h-6 w-6 text-blue-500" />
        </div>
        <div className="ml-4">
          <h3 className="text-lg font-medium text-gray-900 dark:text-white">
            {title}
          </h3>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
            {description}
          </p>
        </div>
      </div>
      {!disabled && (
        <div className="mt-4 flex items-center text-sm text-blue-500">
          Access form
          <ArrowRight className="ml-2 h-4 w-4" />
        </div>
      )}
      {disabled && (
        <div className="absolute inset-0 bg-gray-100 dark:bg-gray-700 bg-opacity-50 rounded-lg flex items-center justify-center">
          <span className="text-sm font-medium text-gray-500 dark:text-gray-400">
            Coming Soon
          </span>
        </div>
      )}
    </div>
  );
};

export default FormsPage;
